var fs = require("fs");
var path = require("path");

var supportedPlatform = ["win32","darwin", "linux"];
var supportedArch = ["x64", "ia32", "arm64"];

if (!supportedPlatform.includes(process.platform)) {
    return;
}

var platformMapping = {
    "win32": "windows",
    "darwin": "macos",
    "linux": "linux"
};

// Returns the distro-specific subfolder under dist/linux/.
function getLinuxDistroSubdir() {
    try {
        var osRelease = fs.readFileSync("/etc/os-release", "utf8");
        var versionMatch = osRelease.match(/^VERSION_ID="?(\d+)/m);
        var majorVersion = versionMatch ? parseInt(versionMatch[1], 10) : 0;
        if (/^ID(?:_LIKE)?=.*\brhel\b/m.test(osRelease)) {
            return majorVersion >= 10 ? "rhel10" : "rhel8_9";
        }
    } catch (e) {}
    return "ubuntu";
}

// If ./dist doesn't exist this is a clean install and binaries don't exist yet
if (fs.existsSync(path.join(__dirname, "dist"))) {
    // Validate that the current system's architecture is supported
    if (supportedArch.includes(process.arch)) {
        var arch = process.arch == "ia32" ? "x86" : process.arch;
        var platform = platformMapping[process.platform];
        var linuxSubdir = process.platform === "linux" ? getLinuxDistroSubdir() : null;
        var sourceDir = linuxSubdir
            ? path.join(__dirname, "dist", platform, linuxSubdir, arch)
            : path.join(__dirname, "dist", platform, arch);
        if (fs.existsSync(sourceDir)) {
            var destDir = path.join(__dirname, "dist");
            var files = fs.readdirSync(sourceDir);
            // Copy both binaries to the root folder
            files.forEach(filename => {
                var sourceFile = path.join(sourceDir, filename);
                var destFile = path.join(destDir, filename);
                fs.copyFileSync(sourceFile, destFile);
            });
        }
    }
}
